+func newDocsCreateCmd(flags *rootFlags) *cobra.Command {
+	var parent string
+
+	cmd := &cobra.Command{
+		Use:   "create <title>",
+		Short: "Create a Google Doc",
+		Args:  cobra.ExactArgs(1),
+		RunE: func(cmd *cobra.Command, args []string) error {
